SELECT p.firstImgUrl,c.classId,p.className,c.coachClassShipId,concat(p.classPrice,'') AS classFee,c.lowestClass
FROM coach_class_ship c LEFT JOIN private_class p ON p.privateClassId = c.classId
WHERE c.coachId = #{coachId}

    limit #{offset}, #{limit}

SELECT COUNT(1)
FROM coach_class_ship c LEFT JOIN private_class p ON p.privateClassId = c.classId
WHERE c.coachId = #{coachId}
